-- 018_expand_full_hospital_staff_templates_to_154.sql
-- Expand standardized EMR staff templates to the canonical 154-role master list.

ON CONFLICT (template_key) DO UPDATE
SET
  title = EXCLUDED.title,
  role_group = EXCLUDED.role_group,
  category = EXCLUDED.category,
  api_role = EXCLUDED.api_role,
  description = EXCLUDED.description,
  sort_order = EXCLUDED.sort_order,
  active = TRUE,
  updated_at = NOW();

-- Deactivate legacy keys from pre-canonical seed that differ only by abbreviation suffixes.
UPDATE staff_role_templates
SET
  active = FALSE,
  updated_at = NOW()
WHERE template_key IN (
  'medical-staff-department-head-hod',
  'medical-staff-general-practitioner-gp',
  'medical-staff-consultant-specialist',
  'surgical-staff-obstetrician-gynecologist-ob-gyn',
  'procedure-based-specialists-intensivist-icu',
  'nursing-staff-nurse-unit-manager-ward-manager',
  'nursing-staff-registered-nurse-rn',
  'nursing-staff-licensed-practical-nurse-lpn',
  'nursing-staff-nurse-practitioner-np'
);